  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is an interactive optimization task involving spatial search and pattern matching. I will delegate the design of the search strategy, the noise-handling logic, and the final implementation structure.",
  "helpers": [
    {
      "label": "search_strategy_designer",
      "instructions": "Design an efficient spatial sampling strategy to locate the polyominoes on the grid. Compare the cost-effectiveness of single-cell queries (q 1) versus multi-cell aggregate queries (q k) given the noise parameter. Propose a method to transition from sparse sampling to dense local probing once a potential oil cell is detected."
    },
    {
      "label": "noise_and_pattern_matcher",
      "instructions": "Develop a mathematical approach to handle the noise in multi-cell aggregate queries. Given a set of known polyomino shapes, define a method to perform template matching or probabilistic inference to identify the exact orientation and position of a shape when the query results are noisy."
    },
    {
      "label": "implementation_architect",
      "instructions": "Outline the structure of the main.py file. Define the interaction loop (reading initial input, writing commands, reading responses), the state management for the grid and discovered cells, and the final submission format (a k x1 y1 ...). Ensure the architecture supports flushing stdout after every command."
    }
  ],
  "synthesis_brief": "Combine the sampling strategy, the noise-robust pattern matching algorithm, and the interactive loop structure into a single, cohesive Python script that minimizes probing cost while maximizing accuracy."
}

